 68 │             arguments: ["find-generic-password", "-s", serviceName, "-w"],
 69 │             timeoutSeconds: timeoutSecs
 70 │         )
 71 │         if result.timedOut {
 72 │             throw ClaudeAuthError.keychainTimeout(serviceName: serviceName, timeoutSeconds: timeoutSecs)
 73 │         }
 74 │         guard result.terminationStatus == 0 else {
 75 │             if serviceName == Self.defaultKeychainService,
 76 │                try await hasStandardAPIKey(timeoutSeconds: timeoutSecs) {
 77 │                 throw ClaudeAuthError.apiKeyOnlyUnsupported(serviceName: Self.apiKeyKeychainService)
 78 │             }
 79 │             throw ClaudeAuthError.keychainAccessDenied(serviceName: serviceName, exitCode: result.terminationStatus)
 80 │         }
 81 │ 
