 83 │               !raw.isEmpty else {
 84 │             throw ClaudeAuthError.keychainEmpty(serviceName: serviceName)
 85 │         }
 86 │ 
 87 │         guard let jsonData = raw.data(using: .utf8) else {
 88 │             throw ClaudeAuthError.keychainParseFailed(serviceName: serviceName, rawPreview: raw)
 89 │         }
 90 │ 
 91 │         let parsed: [String: Any]
 92 │         do {
 93 │             parsed = try JSONSerialization.jsonObject(with: jsonData) as? [String: Any] ?? [:]
 94 │         } catch {
 95 │             throw ClaudeAuthError.keychainParseFailed(serviceName: serviceName, rawPreview: raw)
 96 │         }
 97 │ 
 98 │         guard let oauth = parsed["claudeAiOauth"] as? [String: Any],
 99 │               let token = oauth["accessToken"] as? String,
100 │               !token.isEmpty else {
101 │             throw ClaudeAuthError.keychainParseFailed(serviceName: serviceName, rawPreview: raw)
102 │         }
103 │ 
104 │         if let expiresAtRaw = oauth["expiresAt"], let expiryDate = Self.parseExpiresAt(expiresAtRaw) {
105 │             let now = clock()
106 │             if now.addingTimeInterval(Self.expirySkewSeconds) >= expiryDate {
107 │                 throw ClaudeAuthError.tokenExpired(serviceName: serviceName, expiredAt: expiryDate)
108 │             }
109 │         }
110 │ 
111 │         return ClaudeCredentials(accessToken: token)
112 │     }
