114 │     private func hasStandardAPIKey(timeoutSeconds: Int) async throws -> Bool {
115 │         let result = try await processRunner.run(
116 │             executablePath: "/usr/bin/security",
117 │             arguments: ["find-generic-password", "-s", Self.apiKeyKeychainService, "-w"],
118 │             timeoutSeconds: timeoutSeconds
119 │         )
120 │         guard !result.timedOut, result.terminationStatus == 0,
121 │               let raw = String(data: result.stdout, encoding: .utf8) else {
122 │             return false
123 │         }
124 │         return raw.trimmingCharacters(in: .whitespacesAndNewlines).hasPrefix("sk-ant-api")
125 │     }
126 │ 
127 │     static func parseExpiresAt(_ raw: Any) -> Date? {
128 │         let millis: Double
129 │         switch raw {
130 │         case let value as Double: millis = value
131 │         case let value as Int: millis = Double(value)
132 │         case let value as String:
133 │             guard let parsed = Double(value) else { return nil }
134 │             millis = parsed
135 │         default: return nil
136 │         }
137 │         guard millis.isFinite, millis > 0 else { return nil }
138 │         return Date(timeIntervalSince1970: millis / 1000)
139 │     }
140 │ }

