25	public struct SystemKeychainQuery: KeychainQuerying {
26	    static let timeoutSeconds = 10
27	
28	    public init() {}
29	
30	    public func allPasswords(service: String) async throws -> [Data] {
31	        try await withCheckedThrowingContinuation { continuation in
32	            let callback = OneShotKeychainCallback()
33	
34	            DispatchQueue.global(qos: .userInitiated).async {
35	                callback.resume(continuation, with: Self.queryKeychain(service: service))
36	            }
37	
38	            DispatchQueue.global(qos: .userInitiated).asyncAfter(deadline: .now() + .seconds(Self.timeoutSeconds)) {
39	                callback.resume(
40	                    continuation,
41	                    with: .failure(KeychainQueryError.timeout(service: service, timeoutSeconds: Self.timeoutSeconds))
42	                )
43	            }
44	        }
45	    }
46	
47	    private static func queryKeychain(service: String) -> Result<[Data], Error> {
48	        let query: [CFString: Any] = [
49	            kSecClass: kSecClassGenericPassword,
50	            kSecAttrService: service,
51	            kSecMatchLimit: kSecMatchLimitAll,
52	            kSecReturnData: true,
53	        ]
54	        var result: CFTypeRef?
55	        let status = SecItemCopyMatching(query as CFDictionary, &result)
56	        switch status {
57	        case errSecSuccess:
58	            return .success((result as? [Data]) ?? [])
59	        case errSecItemNotFound:
60	            return .success([])
61	        default:
62	            return .failure(KeychainQueryError.accessDenied(service: service, status: status))
63	        }
64	    }
65	}
66	
67	private final class OneShotKeychainCallback: @unchecked Sendable {
68	    private let lock = NSLock()
69	    private var didResume = false
70	
71	    func resume(_ continuation: CheckedContinuation<[Data], Error>, with result: Result<[Data], Error>) {
72	        lock.lock()
73	        let shouldResume = !didResume
74	        didResume = true
75	        lock.unlock()
76	
77	        guard shouldResume else { return }
78	        continuation.resume(with: result)
79	    }
80	}

