3	/// What `ClaudeCredentialLocator.locate()` produces — a Claude OAuth bearer
4	/// token resolved from the macOS Keychain entry written by the `claude` CLI.
5	public struct ClaudeCredentials: Sendable, Equatable {
6	    public let accessToken: String
7	
8	    public init(accessToken: String) {
9	        self.accessToken = accessToken
10	    }
11	}
12	
13	public enum ClaudeAuthError: Error, CustomStringConvertible {
14	    case keychainAccessDenied(serviceName: String, exitCode: Int32)
15	    case keychainEmpty(serviceName: String)
16	    case keychainTimeout(serviceName: String, timeoutSeconds: Int)
17	    case keychainParseFailed(serviceName: String, rawPreview: String)
18	    case apiKeyOnlyUnsupported(serviceName: String)
19	    /// Access token from the keychain has passed its `expiresAt` timestamp.
20	    /// The user must re-run the `claude` CLI to refresh — the locator is
21	    /// read-only by contract and never invokes the OAuth refresh flow.
22	    case tokenExpired(serviceName: String, expiredAt: Date)
23	
24	    public var description: String {
25	        switch self {
26	        case let .keychainAccessDenied(svc, code):
27	            "Keychain access denied for service '\(svc)' (exit \(code))"
28	        case let .keychainEmpty(svc):
29	            "Keychain item is empty for service '\(svc)'"
30	        case let .keychainTimeout(svc, secs):
31	            "Keychain access timed out after \(secs)s for service '\(svc)'"
32	        case let .keychainParseFailed(svc, preview):
33	            "Failed to parse keychain value for service '\(svc)' — preview: '\(preview.prefix(80))'"
34	        case let .apiKeyOnlyUnsupported(svc):
35	            "Claude Code is authenticated with a standard API key in service '\(svc)'; usage reporting requires Claude Code OAuth credentials"
36	        case let .tokenExpired(svc, expiredAt):
37	            "OAuth access token for service '\(svc)' expired at \(expiredAt)"
38	        }
39	    }
40	}
41	
42	/// Reads the Claude OAuth access token from the macOS Keychain entry
43	/// written by the `claude` CLI. Read-only by contract — never calls
44	/// `SecItemAdd`, `SecItemUpdate`, `SecItemDelete`; never invokes
45	/// `claude auth login`; never writes any vendor file.
46	public actor ClaudeCredentialLocator: CredentialLocator {
47	    public typealias Credentials = ClaudeCredentials
48	
49	    public static let defaultKeychainService = "Claude Code-credentials"
50	    public static let apiKeyKeychainService = "Claude Code"
51	    /// Long enough for a cached keychain lookup; short enough to avoid
52	    /// stalling the poller.
53	    public static let keychainTimeoutSeconds = SystemKeychainQuery.timeoutSeconds
54	    /// Treat the token as expired this many seconds before the actual
55	    /// `expiresAt` to avoid the race where we send a request just as the
56	    /// token flips invalid and burn a 401 we could have skipped.
57	    public static let expirySkewSeconds: TimeInterval = 60
58	
59	    private let keychainServiceName: String
60	    private let keychainQuerying: any KeychainQuerying
61	    private let logger: FileLogger
62	    private let clock: @Sendable () -> Date
63	
64	    public init(
65	        keychainServiceName: String = ClaudeCredentialLocator.defaultKeychainService,
66	        keychainQuerying: any KeychainQuerying = SystemKeychainQuery(),
67	        logger: FileLogger = Loggers.claude,
68	        clock: @escaping @Sendable () -> Date = { Date() }
69	    ) {
70	        self.keychainServiceName = keychainServiceName
71	        self.keychainQuerying = keychainQuerying
72	        self.logger = logger
73	        self.clock = clock
74	    }
75	
76	    public func locate() async throws -> ClaudeCredentials {
77	        let serviceName = keychainServiceName
78	        let now = clock()
79	
80	        let allEntries: [Data]
81	        do {
82	            allEntries = try await keychainQuerying.allPasswords(service: serviceName)
83	        } catch {
84	            throw try await mapKeychainError(error, serviceName: serviceName)
85	        }
86	
87	        guard !allEntries.isEmpty else {
88	            if serviceName == Self.defaultKeychainService, try await hasStandardAPIKey() {
89	                throw ClaudeAuthError.apiKeyOnlyUnsupported(serviceName: Self.apiKeyKeychainService)
90	            }
91	            throw ClaudeAuthError.keychainEmpty(serviceName: serviceName)
92	        }
93	
94	        // Parse every entry; keep those with a non-empty claudeAiOauth.accessToken.
95	        // Multiple entries for the same service arise when one holds MCP plugin OAuth
96	        // state (acct=unknown) and another holds the actual usage bearer (acct=$USER).
97	        var candidates: [(token: String, expiryDate: Date?)] = []
98	        var lastRawPreview = ""
99	
100	        for data in allEntries {
101	            guard let raw = String(data: data, encoding: .utf8)?
102	                .trimmingCharacters(in: .whitespacesAndNewlines),
103	                  !raw.isEmpty else {
104	                continue
105	            }
106	
107	            let parsed: [String: Any]
108	            do {
109	                parsed = (try JSONSerialization.jsonObject(with: data) as? [String: Any]) ?? [:]
110	            } catch {
111	                lastRawPreview = raw
112	                continue
113	            }
114	
115	            guard let oauth = parsed["claudeAiOauth"] as? [String: Any],
116	                  let token = oauth["accessToken"] as? String,
117	                  !token.isEmpty else {
118	                lastRawPreview = raw
119	                continue
120	            }
121	
122	            guard !candidates.contains(where: { $0.token == token }) else { continue }
123	
124	            // expiresAt is a Unix millisecond timestamp written by the `claude` CLI
125	            // (Node.js convention — `Date.now()`). A missing or unparseable value
126	            // skips the local check: the API call still happens and a 401 will
127	            // surface as token_expired downstream.
128	            let expiryDate = oauth["expiresAt"].flatMap { Self.parseExpiresAt($0) }
129	            candidates.append((token: token, expiryDate: expiryDate))
130	        }
131	
132	        let skewedNow = now.addingTimeInterval(Self.expirySkewSeconds)
133	        if let bestKnownExpiry = candidates.first(where: { candidate in
134	            guard let expiryDate = candidate.expiryDate else { return false }
135	            return skewedNow < expiryDate
136	        }) {
137	            return ClaudeCredentials(accessToken: bestKnownExpiry.token)
138	        }
139	
140	        if let fallbackUnknownExpiry = candidates.first(where: { $0.expiryDate == nil }) {
141	            return ClaudeCredentials(accessToken: fallbackUnknownExpiry.token)
142	        }
143	
144	        if let expired = candidates.first, let expiredAt = expired.expiryDate {
145	            throw ClaudeAuthError.tokenExpired(serviceName: serviceName, expiredAt: expiredAt)
146	        }
147	
148	        if !lastRawPreview.isEmpty {
149	            throw ClaudeAuthError.keychainParseFailed(serviceName: serviceName, rawPreview: lastRawPreview)
150	        }
151	
152	        throw ClaudeAuthError.keychainEmpty(serviceName: serviceName)
153	    }
154	
155	    private func hasStandardAPIKey() async throws -> Bool {
156	        let entries: [Data]
157	        do {
158	            entries = try await keychainQuerying.allPasswords(service: Self.apiKeyKeychainService)
159	        } catch {
160	            return false
161	        }
162	        return entries.contains {
163	            String(data: $0, encoding: .utf8)?
164	                .trimmingCharacters(in: .whitespacesAndNewlines)
165	                .hasPrefix("sk-ant-api") == true
166	        }
167	    }
168	
169	    private func mapKeychainError(_ error: Error, serviceName: String) async throws -> ClaudeAuthError {
170	        if let qErr = error as? KeychainQueryError {
171	            switch qErr {
172	            case let .timeout(_, secs):
173	                return ClaudeAuthError.keychainTimeout(serviceName: serviceName, timeoutSeconds: secs)

